/**
 * number type changed event handler
 *
 *
 * @private
 * @memberOf bxInput
 */
function _numberTypeChangedHandler(){

    const $input = this;
    const $wrapper = $input.parents(`.${INPUT_SELECTOR.numberTypeWrap}`);

    const value = $input.val();

    const min = $input.prop('min');
    const max = $input.prop('max');

    let prevValue = $input.attr('data-prev-value') || '';
    let currentValue = _.trim(value);

    const currentValueInfo = _getQualifiedValueInfo(min, max, currentValue);

    currentValue = currentValueInfo.value;

    const item = {
        prevValue: prevValue,
        currentValue: currentValue
    };

    _setDisabledIcon($wrapper, currentValueInfo.state);

    if (prevValue !== currentValue){
        $input.prop('bxchanged').call($input, item);
    }

    $input.val(currentValue);
}

/**
 * . 키 down 이벤트 핸들러 (number type)
 *
 * @param {object} event 객체
 * @return {boolean} keydown 허용 여부
 *
 * @private
 * @memberOf bxInput
 */
function _handleDotKeyDown(e = {}){

    let input = e.currentTarget;
    let $input = $(input);
    let value = _.trim($input.val());

    if (input.selectionStart === 0){

        $input.val('0.');
        return false;
    }

    let cursorIndex = value.indexOf('.');

    if (cursorIndex !== -1){

        input.selectionStart = cursorIndex;
        input.selectionEnd = cursorIndex;

        return false;
    }

    if (value.substr(0, input.selectionStart) === '-'){

        $input.val('-0.' + value.substr(1, value.length - 1));

        return false;
    }
}

/**
 * - 키 down 이벤트 핸들러 (number type)
 *
 * @param {object} event 객체
 * @return {boolean} keydown 허용 여부
 *
 * @private
 * @memberOf bxInput
 */
function _handleMinusKeyDown(e = {}){

    let input = e.currentTarget;
    let $input = $(input);
    let value = _.trim($input.val());

    if (input.selectionStart === 0) return true;

    if (value.indexOf('-') === -1) $input.val('-' + value);
    else $input.val(value.replace('-', ''));

    return false;
}

/**
 * number type blur event handler (숫자 유효성 check)
 *
 * @param {object} event 객체
 *
 * @private
 * @memberOf bxInput
 */
function _numberTypeBlurHandler(e = {}){

    const $elem = $(e.target);

    const max = $elem.prop('max');
    const min = $elem.prop('min');
    const step = $elem.prop('step').replace(/\d/g, '0');

    const $input = $(e.currentTarget);
    let value = _.trim($input.val());

    if (value.charAt(value.length - 1) === '.'){
        $input.val(value.slice(0, -1));
    }

    if (value === '-'){
        $input.val('');
        return;
    }

    value = _getQualifiedValueInfo(min, max, value).value;

    if (value.length === 2 && value.indexOf('.') === 1) {
        value = _convertFloatingPointToDecimalPoint(value, step);
    }

    $elem.attr('data-prev-value', value);
    $input.val(value);
}

/**
 * number type input의 값 증가 함수
 *
 * @param {object} 옵션 객체
 *
 * @private
 * @memberOf bxInput
 */
function _increaseNumberTypeValue(e = {}, opts = {}){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw(BxInputNumber, 'opts', 'type');
    }

    const $this = $(this);

    // TODO - 아래 코드 변경되어야 한다. [변경완]
    if ($this.hasClass('placeholder')){
        $this.val('0');
        $this.removeClass('placeholder');
    }
    if ($this.prop('disabled')) return;

    const min = $this.prop('min');
    const max = $this.prop('max');
    const step = $this.prop('step');

    let currentValue = _.trim($this.val()) || '0';

    $this.attr('data-prev-value', currentValue);
    currentValue = _convertFloatingPointToDecimalPoint(currentValue, step);
    currentValue = _getQualifiedValueInfo(min, max, _.toString(currentValue)).value;

    $this.val(currentValue);
}

/**
 * number type input의 값 감소 함수
 *
 * @param {object} 옵션 객체
 *
 * @private
 * @memberOf bxInput
 */
function _decreaseNumberTypeValue(e = {}, opts = {}){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw(BxInputNumber, 'opts', 'type');
    }

    let $this = $(this);

    if ($this.hasClass('placeholder')){
        $this.val('0');
        $this.removeClass('placeholder');
    }
    if ($this.prop('disabled')) return;

    const min = $this.prop('min');
    const max = $this.prop('max');
    const step = `-${$this.prop('step')}`;

    let currentValue = _.trim($this.val()) || '0';

    $this.attr('data-prev-value', currentValue);

    currentValue = _convertFloatingPointToDecimalPoint(currentValue, step);
    currentValue = _getQualifiedValueInfo(min, max, currentValue).value;

    $this.val(currentValue);
}

/**
 * 부동소수점 연산 함수
 * http://stackoverflow.com/questions/588004/is-floating-point-math-broken 참고
 *
 * @param {string} value
 * @param {string} step
 *
 * @private
 * @memberOf bxInput
 */
function _convertFloatingPointToDecimalPoint(value = '', step = '1'){

    if (!_.isString(value)){
        CONSOLE.prop.throw(BxInputNumber, 'value', 'type');
    }

    if (!TYPE.isNumber(step)){
        CONSOLE.prop.throw(BxInputNumber, 'step', 'type');
    }

    let ret = '';

    if (value){

        const nValue = parseFloat(value || 0);
        const sStep = step;

        if (value.indexOf('.') === -1 && sStep.indexOf('.') === -1){
            ret = nValue + parseFloat(step);
        }
        else{
            // 실수를 정수로 만들기 위한 소수자리 값을 구한다.
            const vpl = (value.split('.')[1] || '').length;
            const spl = (sStep.split('.')[1] || '').length;

            const point = vpl > spl ? vpl : spl;

            const T = Number('1e' + point);
            // 실수를 정수로 만들어 연산한 후, 다시 실수로 변환하여 그 값을 반환한다.
            ret = (Math.round((nValue + parseFloat(step)) * T) / T).toFixed(point);
        }
    }
    return ret.toString();
}

/**
 * number type input의 + 버튼 이벤트 세팅 함수
 *
 * @private
 * @memberOf bxInput
 */
function _setNumberTypeIncBtnHandler($elem = null, opts = {}){

    $elem.on('click', `.${INPUT_SELECTOR.incBtn}`, e => {

        let $component = $(e.delegateTarget).find(`.${INPUT_SELECTOR.bxInputWrap}`);
        let $input = $component.find(`.${INPUT_SELECTOR.bxInput}`);

        _increaseNumberTypeValue.call($input, e, opts);
        _numberTypeChangedHandler.call($input);
    });
}

/**
 * number type input의 - 버튼 이벤트 세팅 함수
 *
 * @private
 * @memberOf bxInput
 */
function _setNumberTypeDecBtnHandler($elem = null, opts = {}){

    $elem.on('click', `.${INPUT_SELECTOR.decBtn}`, (e) => {

        let $component = $(e.delegateTarget).find(`.${INPUT_SELECTOR.bxInputWrap}`);
        let $input = $component.find(`.${INPUT_SELECTOR.bxInput}`);

        _decreaseNumberTypeValue.call($input, e, opts);
        _numberTypeChangedHandler.call($input);
    });
}

/**
 * number type의 검증된 숫자 값을 반환하는 함수
 * @param {string} min
 * @param {string} max
 * @param {string} value
 * @returns {{value: string, state: string}}
 * @private
 */
function _getQualifiedValueInfo(min = '0', max = '0', value = ''){

    if (!TYPE.isNumber(min)){
        CONSOLE.prop.throw(BxInputNumber, 'min', 'type');
    }

    if (!TYPE.isNumber(max)){
        CONSOLE.prop.throw(BxInputNumber, 'max', 'type');
    }

    if (!_.isString(value)){
        CONSOLE.prop.throw(BxInputNumber, 'value', 'type');
    }

    let state = '';

    if (TYPE.isNumber(value)){

        state = 'between';

        const _value = parseFloat(value);
        const _min = parseFloat(min);
        const _max = parseFloat(max);

        if (_value <= _min){
            value = min;
            state = 'min';
        }

        if (_value >= _max){
            value = max;
            state = 'max';
        }

        if (value.indexOf('.') === 0) {
            value = _value;
        }
    }

    return {
        value: value,
        state: state
    };
}

/**
 * bxInput Number Type 의 Icon 및 structure css 재조정 함수
 * - safari 5.1.7 에서 float 로 인해 structure 구조 변경. calc 에 대한 연산 적용.
 * @param {{}} $container - $container instance
 * @param {{}} options - component option 객체
 * @private
 * @memberOf bxInput
 */
function _setIconPosition($elem = null, options = {}){

    if (_.isNull($elem)){
        CONSOLE.prop.throw(BxInputNumber, '$elem', 'type');
    }

    if (!_.isFunction($elem.get) || !_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxInputNumber, '$elem', 'type');
    }

    if (!_.isPlainObject(options)){
        CONSOLE.prop.throw(BxInputNumber, 'options', 'type');
    }

    // 하위 작업은 window browser 에서 아이콘의 위치가 calc 로 인해 밀려나는 문제로 인해 pixel 연산 후 적용함.
    let {buttonType} = options;

    let selectorObj = UTIL.getSelectorInstance($elem, {
        quantity: 'btn-quantity',
        ctrlIcon: 'bx-ctrl-icon'
    });

    selectorObj.wrap = $elem;
    let $ctrlIcon = selectorObj.ctrlIcon;

    $ctrlIcon.length > 1 && Object.assign(selectorObj, {
        $ctrlIcons: $ctrlIcon
    });

    _.isEqual(buttonType, 'default') && _setDefaultIconPosition(selectorObj);

    _.isEqual(buttonType, 'inline') && _setInlineIconPosition(selectorObj);

    _.isEqual(buttonType, 'side') && _setSideIconPosition(selectorObj);
}

/**
 * default buttonType 아이콘 포지션 설정 함수
 * @param {{}} [$wrap=null] wrap 인스턴스
 * @param {{}}[$quantity=null] quantity 인스턴스
 * @param {{}}[$ctrlIcon=null] icon 인스턴스
 * @private
 */
function _setDefaultIconPosition({wrap: $wrap = null, quantity: $quantity = null, ctrlIcon: $ctrlIcon = null} = {}){

    let mid = Math.floor(($wrap.height() - 1) / 2);

    $($quantity[0]).height(mid);

    let iTop = ($quantity.height() - $ctrlIcon.height()) / 2,
        iLeft = ($quantity.width() - $ctrlIcon.width()) / 2;

    UTIL.setPosition($ctrlIcon, {top: iTop, left: iLeft});
}

/**
 * inline buttonType 아이콘 포지션 설정 함수
 * @param {{}} [$wrap=null] wrap 인스턴스
 * @param {{}}[$quantity=null] quantity 인스턴스
 * @param {{}}[$ctrlIcon=null] icon 인스턴스
 * @private
 */
function _setInlineIconPosition({wrap: $wrap = null, quantity: $quantity = null, ctrlIcon: $ctrlIcon = null} = {}){

    let top = ($wrap.height() - 15) / 2;

    UTIL.setPosition($quantity, {top: top});

    let iTop = ($quantity.height() - $ctrlIcon.height()) / 2 + 1,
        iLeft = ($quantity.width() - $ctrlIcon.width()) / 2;

    UTIL.setPosition($ctrlIcon, {top: iTop, left: iLeft});
}

/**
 * side buttonType 아이콘 포지션 설정 함수
 * @param {{}} [$wrap=null] wrap 인스턴스
 * @param {{}}[$quantity=null] quantity 인스턴스
 * @param {{}}[$ctrlIcons=null] icon 인스턴스 배열
 *
 * @private
 */
function _setSideIconPosition({quantity: $quantity = null, $ctrlIcons = null} = {}){

    let top = ($quantity.height() / 2 - 5);
    let left = top;

    for (let i = 0; i < $ctrlIcons.length; i++){

        let $icon = $($ctrlIcons[i]);

        UTIL.setPosition($icon, {top: top, left: left});
    }
}

/**
 * 최대, 최소값 인 경우 이미지 disabled 설정 함수
 * @param {object} [$wrapper={}] input wrapper
 * @param {string} [state=''] 변경 할 icon state
 *
 * @private
 */
function _setDisabledIcon($elem = null, state = ''){

    let $i = $elem.find('i');

    let disabled = INPUT_SELECTOR.disabled;

    if (state === 'between'){
        $i.removeClass(disabled);
    }
    else if (state === 'max'){
        $i.removeClass(disabled).filter(`.${INPUT_SELECTOR.incBtn}`).addClass(disabled);
    }
    else if (state === 'min'){
        $i.removeClass(disabled).filter(`.${INPUT_SELECTOR.decBtn}`).addClass(disabled);
    }
}

module.exports = BxInputNumber;
